    {
      "id": 7,
      "translated": "\"Like the trained illustrations for 'Secret Distance' and 'Where Shall This Path Lead?',\""
    },
    {
      "id": 8,
      "translated": "\"Wait, 'Where Shall This Path Lead?'...\""
    },
    {
      "id": 9,
      "translated": "\"Mizuki is shown in a space filled with torsos.\""
